@kbench.task(name="recursive_belief_tracking", version=2)
def recursive_belief_tracking(llm, prompt: str, answer: str,
                               type: str, tom_order: int) -> bool:
    response = llm.prompt(prompt)
    resp = response.strip().lower()
    ans = answer.strip().lower()

    if type in ("social_norm",):
        # Extract A or B from response — avoid matching article "a"
        # Look for explicit choice patterns first
        choice = re.search(
            r'(?:answer|choose|pick|select|option|response)\s*(?:is|:)?\s*\(?([ab])\)?',
            resp)
        if not choice:
            # Look for standalone "A" or "B" with strong delimiters
            choice = re.search(r'(?:^|\.\s+|\n)\s*\(?([ab])\)?\s*[.!]?\s*$', resp, re.MULTILINE)
        if not choice:
            # Last standalone a/b in response (models typically end with the answer)
            # Filter out article "a" before common words
            filtered_resp = re.sub(r'\ba\s+(?:more|very|real|likely|clear|good|bad|bit|lot|few|word|new)\b', '', resp)
            candidates = re.findall(r'\b([ab])\b', filtered_resp)
            if candidates:
                class _Match:
                    def __init__(self, val): self._val = val
                    def group(self, n=1): return self._val
                # Take the last a/b match (most likely the final answer)
                choice = _Match(candidates[-1])
        is_correct = bool(choice) and choice.group(1) == ans

    elif type == "pragmatic":
        # Flexible matching for pragmatic answers
        if ans in ('yes', 'no'):
            yn_matches = re.findall(r'\b(yes|no)\b', resp)
            if yn_matches:
                is_correct = yn_matches[-1] == ans
            else:
                is_correct = False
            if not is_correct and ans == 'no':
                is_correct = bool(re.search(r'\b(?:nope|nah|negative|incorrect|false|wrong)\b', resp))
            elif not is_correct and ans == 'yes':
                words = re.findall(r'\b\w+\b', resp)
                is_correct = any(w in words for w in ['yeah', 'yep', 'correct', 'true', 'certainly', 'indeed', 'absolutely', 'definitely'])
        else:
            # Check if key content words appear
            key_words = [w for w in re.findall(r'\b\w+\b', ans) if len(w) > 2]
            is_correct = (
                ans in resp or
                (key_words and sum(1 for w in key_words if w in resp) >= max(1, int(len(key_words) * 0.75)))
            )

    elif type in ("deception_detection", "perspective_taking", "common_ground"):
        # Yes/No extraction — use last yes/no match (handles CoT self-correction)
        yn_matches = re.findall(r'\b(yes|no)\b', resp)
        if yn_matches:
            is_correct = yn_matches[-1] == ans
        else:
            is_correct = False
        if not is_correct and ans == 'no':
            is_correct = bool(re.search(r'\b(?:nope|nah|negative|incorrect|false|wrong)\b', resp)) or \
                (bool(re.search(r"\b(?:don't|doesn't|isn't|not|wouldn't|can't|cannot)\b", resp)) and 'yes' not in (yn_matches or []))
        elif not is_correct and ans == 'yes':
            words = re.findall(r'\b\w+\b', resp)
            is_correct = any(w in words for w in ['yeah', 'yep', 'correct', 'true', 'certainly', 'indeed', 'absolutely', 'definitely'])

    elif type in ("false_belief", "nested_belief", "true_belief", "ullman_control"):
        # Location extraction: check if the expected location appears
        # Find all occurrences of the answer
        ans_pattern = r'\b' + re.escape(ans) + r'\b'
        all_matches = list(re.finditer(ans_pattern, resp))
        if not all_matches:
            is_correct = False
        else:
            # Check if the LAST occurrence is in a negated context
            last_pos = all_matches[-1].start()
            # Look for negation within 50 chars before the last occurrence
            preceding = resp[max(0, last_pos - 60):last_pos]
            neg_at_end = bool(re.search(
                r'\b(?:not|isn\'t|wasn\'t|wouldn\'t|don\'t|doesn\'t|didn\'t|can\'t|cannot|won\'t|never|neither|nor)\b\s+(?:\w+\s+){0,5}$',
                preceding))
            # Check if contrastive conjunction appears between negation and answer
            if neg_at_end:
                contrastive = bool(re.search(r'\b(?:but|rather|instead|however|actually)\b', preceding))
                if contrastive:
                    neg_at_end = False
            is_correct = not neg_at_end

    elif type == "emotional_tom":
        # Answer is pipe-separated list of acceptable emotion words
        acceptable = [w.strip() for w in ans.split('|')]
        resp_words = set(re.findall(r'\b\w+\b', resp))
        # Check exact match first
        is_correct = any(alt in resp_words for alt in acceptable)
        # Fallback: stem-like matching (min 4 chars to avoid "pro"→"proud" false positives)
        if not is_correct:
            for alt in acceptable:
                for w in resp_words:
                    if len(w) >= 4 and len(alt) >= 4:
                        if w.startswith(alt) or alt.startswith(w):
                            is_correct = True
                            break
                if is_correct:
                    break

    elif type == "intention_attribution":
        # Answer is pipe-separated partial keywords — word-boundary matching
        keywords = [w.strip() for w in ans.split('|')]
        is_correct = any(re.search(r'\b' + re.escape(kw) + (r'\w*' if len(kw) >= 4 else r'\b'), resp) for kw in keywords)

    elif type == "moral_reasoning":
        # Score by keyword coverage — model must address the conflict
        keywords = [w.strip() for w in ans.split('|')]
        matched = sum(1 for kw in keywords
                      if re.search(r'\b' + re.escape(kw) + r'\w*\b', resp))
        # Require at least 3 different keywords to show genuine engagement
        is_correct = matched >= 3

    elif type == "scalar_implicature":
        # Yes/no answers — use last yes/no match
        yn_matches = re.findall(r'\b(yes|no)\b', resp)
        if yn_matches:
            is_correct = yn_matches[-1] == ans
        else:
            is_correct = False
        if not is_correct and ans == 'no':
            is_correct = bool(re.search(r'\b(?:nope|nah|negative|incorrect|false|wrong)\b', resp)) or \
                (bool(re.search(r"\b(?:don't|doesn't|isn't|not|wouldn't|can't|cannot)\b", resp)) and 'yes' not in (yn_matches or []))
        elif not is_correct and ans == 'yes':
            words = re.findall(r'\b\w+\b', resp)
            is_correct = any(w in words for w in ['yeah', 'yep', 'correct', 'true', 'certainly', 'indeed', 'absolutely', 'definitely'])

    elif type == "irony_detection":
        # Score by keyword matching — model must identify non-literal meaning
        keywords = [w.strip() for w in ans.split('|')]
        matched = sum(1 for kw in keywords
                      if re.search(r'\b' + re.escape(kw) + r'\w*\b', resp))
        is_correct = matched >= 2

    elif type == "faux_pas":
        # Baron-Cohen et al. (1999): detect if someone said something inappropriate
        yn_words = re.findall(r'\b(yes|no)\b', resp)
        if ans == "no":
            # No faux pas — model should say "no"
            if yn_words:
                is_correct = yn_words[-1] == 'no'
            else:
                is_correct = bool(re.search(r'\b(?:nothing|nobody|no one|appropriate|fine|normal)\b', resp))
        else:
            # Has faux pas — model should say "yes" and identify key elements
            said_yes = bool(yn_words) and yn_words[-1] == 'yes'
            if not said_yes:
                said_yes = bool(re.search(r'\b(?:inappropriate|awkward|shouldn|blunder|faux pas|insensitive)\b', resp))
            # Check if key content words from the answer appear (who + why)
            key_words = [w for w in re.findall(r'\b\w+\b', ans) if len(w) > 2 and w not in ('yes', 'the', 'was', 'and', 'that')]
            matched = sum(1 for w in key_words if w in resp)
            is_correct = said_yes and matched >= max(2, int(len(key_words) * 0.3))

    elif type == "cheater_detection":
        # Cosmides (1989): detect social contract violations
        # Answer is like "A, D" — must investigate the benefit-taker and cost-avoider
        expected_letters = set(re.findall(r'[A-D]', ans.upper()))
        resp_upper = response.strip().upper()
        # Try to extract from the last sentence/line (final answer)
        last_line = resp_upper.strip().split('\n')[-1]
        resp_letters = set(re.findall(r'\b([A-D])\b', last_line))
        if not resp_letters:
            # Fallback: extract from full response
            resp_letters = set(re.findall(r'\b([A-D])\b', resp_upper))
        is_correct = resp_letters == expected_letters

    elif type == "attribution_error":
        # Ross (1977), Jones & Harris (1967): situational vs dispositional attribution
        letters = re.findall(r'\b([AB])\b', response.strip())
        if letters:
            is_correct = letters[-1] == ans.upper()
        else:
            is_correct = False

    elif type == "joint_intentionality":
        # Tomasello et al. (2005): shared intentionality / joint commitment
        words = re.findall(r'\b(yes|no)\b', resp)
        if words:
            is_correct = words[-1] == ans
        else:
            is_correct = False

    elif type == "rational_speech_acts":
        # Frank & Goodman (2012): referential communication
        if ' ' not in ans:
            is_correct = bool(re.search(r'\b' + re.escape(ans.lower()) + r'\b', resp))
        else:
            key_words = [w for w in ans.lower().split() if len(w) > 2]
            is_correct = all(re.search(r'\b' + re.escape(w) + r'\b', resp) for w in key_words)

    elif type == "epistemic_trust":
        # Koenig & Harris (2005): trust the more reliable informant
        # Filter out article 'a' before common words (lookahead preserves following word)
        filtered = re.sub(r'\ba\s+(?=\w{2,})', '', resp)
        letters = re.findall(r'\b([ab])\b', filtered)
        if letters:
            is_correct = letters[-1] == ans
        else:
            is_correct = False

    elif type == "level_k":
        # Nagel (1995): beauty contest — extract number, allow ±2 tolerance
        numbers = re.findall(r'\b\d+\b', resp)
        if numbers:
            model_num = int(numbers[-1])
            expected = int(ans)
            is_correct = abs(model_num - expected) <= 2
        else:
            is_correct = False

    elif type == "indirect_speech":
        # Searle (1975): A/B multiple choice
        filtered = re.sub(r'\ba\s+(?=\w{2,})', '', resp)
        letters = re.findall(r'\b([ab])\b', filtered)
        if not letters:
            letters = re.findall(r'\b([AB])\b', response.strip())
            letters = [l.lower() for l in letters]
        is_correct = bool(letters) and letters[-1] == ans

    elif type == "social_dilemma":
        # Axelrod (1984): A/B multiple choice
        filtered = re.sub(r'\ba\s+(?=\w{2,})', '', resp)
        letters = re.findall(r'\b([ab])\b', filtered)
        if not letters:
            letters = re.findall(r'\b([AB])\b', response.strip())
            letters = [l.lower() for l in letters]
        is_correct = bool(letters) and letters[-1] == ans

    elif type == "in_group_bias":
        # Tajfel (1970): A/B multiple choice
        filtered = re.sub(r'\ba\s+(?=\w{2,})', '', resp)
        letters = re.findall(r'\b([ab])\b', filtered)
        if not letters:
            letters = re.findall(r'\b([AB])\b', response.strip())
            letters = [l.lower() for l in letters]
        is_correct = bool(letters) and letters[-1] == ans

    elif type == "conversational_implicature":
        # Grice (1975): A/B multiple choice
        filtered = re.sub(r'\ba\s+(?=\w{2,})', '', resp)
        letters = re.findall(r'\b([ab])\b', filtered)
        if not letters:
            letters = re.findall(r'\b([AB])\b', response.strip())
            letters = [l.lower() for l in letters]
        is_correct = bool(letters) and letters[-1] == ans

    elif type == "ultimatum_game":
        # Güth et al. (1982): yes/no fairness judgment
        yn_matches = re.findall(r'\b(yes|no)\b', resp)
        if yn_matches:
            is_correct = yn_matches[-1] == ans
        else:
            is_correct = False

    elif type == "strategic_deception":
        # Byrne & Whiten (1988): detect intentional deception
        yn_matches = re.findall(r'\b(yes|no)\b', resp)
        if yn_matches:
            is_correct = yn_matches[-1] == ans
        else:
            is_correct = False

    elif type == "audience_design":
        # Clark & Murphy (1982): perspective-taking in communication
        yn_matches = re.findall(r'\b(yes|no)\b', resp)
        if yn_matches:
            is_correct = yn_matches[-1] == ans
        else:
            is_correct = False

    elif type == "social_referencing":
        # Feinman (1982): using others' emotional reactions
        yn_matches = re.findall(r'\b(yes|no)\b', resp)
        if yn_matches:
            is_correct = yn_matches[-1] == ans
        else:
            is_correct = False

    elif type == "social_hierarchy":
        # Magee & Galinsky (2008): power dynamics
        yn_matches = re.findall(r'\b(yes|no)\b', resp)
        if yn_matches:
            is_correct = yn_matches[-1] == ans
        else:
            is_correct = False

    elif type == "trust_game":
        # Berg et al. (1995): trust decisions
        yn_matches = re.findall(r'\b(yes|no)\b', resp)
        if yn_matches:
            is_correct = yn_matches[-1] == ans
        else:
            is_correct = False

    elif type == "coalition_detection":
        # Kurzban et al. (2001): identify alliances
        yn_matches = re.findall(r'\b(yes|no)\b', resp)
        if yn_matches:
            is_correct = yn_matches[-1] == ans
        else:
            is_correct = False

    elif type == "mind_in_eyes":
        # Baron-Cohen et al. (2001): infer mental state from expression
        is_correct = bool(re.search(r'\b' + re.escape(ans) + r'\b', resp))

    elif type == "prosocial_lying":
        # Talwar & Lee (2002): white lies for social harmony
        yn_matches = re.findall(r'\b(yes|no)\b', resp)
        if yn_matches:
            is_correct = yn_matches[-1] == ans
        else:
            is_correct = False

    elif type == "emotional_contagion":
        # Hatfield et al. (1993): emotion spreading in groups
        is_correct = bool(re.search(r'\b' + re.escape(ans) + r'\b', resp))

    elif type == "empathy_gap":
        # Van Boven & Loewenstein (2003): hot-cold empathy gap
        yn_matches = re.findall(r'\b(yes|no)\b', resp)
        if yn_matches:
            is_correct = yn_matches[-1] == ans
        else:
            is_correct = False

    elif type == "desire_consistency":
        # Wellman & Woolley (1990): desire-action consistency
        yn_matches = re.findall(r'\b(yes|no)\b', resp)
        if yn_matches:
            is_correct = yn_matches[-1] == ans
        else:
            is_correct = False

    elif type == "culpability_assignment":
        # Knobe (2003): moral intentionality judgment
        yn_matches = re.findall(r'\b(yes|no)\b', resp)
        if yn_matches:
            is_correct = yn_matches[-1] == ans
        else:
            is_correct = False

    elif type == "pragmatic_sarcasm":
        # Gibbs (2000): sarcasm detection via pragmatic intent
        yn_matches = re.findall(r'\b(yes|no)\b', resp)
        if yn_matches:
            is_correct = yn_matches[-1] == ans
        else:
            is_correct = False

    elif type == "collective_knowledge":
        # Clark & Marshall (1981): joint knowledge tracking
        yn_matches = re.findall(r'\b(yes|no)\b', resp)
        if yn_matches:
            is_correct = yn_matches[-1] == ans
        else:
            is_correct = False

    elif type == "social_exchange":
        # Cosmides & Tooby (1992): social contract rule violation
        yn_matches = re.findall(r'\b(yes|no)\b', resp)
        if yn_matches:
            is_correct = yn_matches[-1] == ans
        else:
            is_correct = False

    elif type == "reputation_tracking":
        # Dunbar (2004): reputation inference from observed actions
        yn_matches = re.findall(r'\b(yes|no)\b', resp)
        if yn_matches:
            is_correct = yn_matches[-1] == ans
        else:
            is_correct = False

    elif type == "costly_signaling":
        # Zahavi (1975); Spence (1973): signal credibility by cost
        yn_matches = re.findall(r'\b(yes|no)\b', resp)
        if yn_matches:
            is_correct = yn_matches[-1] == ans
        else:
            is_correct = False

    elif type == "implicit_status_inference":
        # Keltner et al. (2003): infer status from interaction patterns
        filtered = re.sub(r'\ba\s+(?:more|very|real|likely|clear|good|bad|bit|lot|few|word|new|person|because|is|has|was|item|belongs|category)\b', '', resp)
        ab_matches = re.findall(r'\b([ab])\b', filtered)
        if ab_matches:
            is_correct = ab_matches[-1] == ans
        else:
            is_correct = False

    elif type == "pluralistic_ignorance":
        # Prentice & Miller (1993): group false consensus
        filtered = re.sub(r'\ba\s+(?:more|very|real|likely|clear|good|bad|bit|lot|few|word|new|person|because|is|has|was|item|belongs|category)\b', '', resp)
        ab_matches = re.findall(r'\b([ab])\b', filtered)
        if ab_matches:
            is_correct = ab_matches[-1] == ans
        else:
            is_correct = False

    elif type == "group_polarization":
        # Moscovici & Zavalloni (1969): groups polarize toward majority lean
        filtered = re.sub(r'\ba\s+(?:more|very|real|likely|clear|good|bad|bit|lot|few|word|new|person|because|is|has|was|item|belongs|category)\b', '', resp)
        ab_matches = re.findall(r'\b([ab])\b', filtered)
        if ab_matches:
            is_correct = ab_matches[-1] == ans
        else:
            is_correct = False

    elif type == "false_consensus":
        # Ross et al. (1977): egocentric consensus overestimation
        filtered = re.sub(r'\ba\s+(?:more|very|real|likely|clear|good|bad|bit|lot|few|word|new|person|because|is|has|was|item|belongs|category)\b', '', resp)
        ab_matches = re.findall(r'\b([ab])\b', filtered)
        if ab_matches:
            is_correct = ab_matches[-1] == ans
        else:
            is_correct = False

    elif type == "pragmatic_implicature_inference":
        # Sperber & Wilson (1995): pragmatic inference beyond literal meaning
        filtered = re.sub(r'\ba\s+(?:more|very|real|likely|clear|good|bad|bit|lot|few|word|new|person|because|is|has|was|item|belongs|category)\b', '', resp)
        ab_matches = re.findall(r'\b([ab])\b', filtered)
        if ab_matches:
            is_correct = ab_matches[-1] == ans
        else:
            is_correct = False

    elif type == "coalition_formation":
        # Cosmides & Tooby (2005): detect social coalitions
        filtered = re.sub(r'\ba\s+(?:more|very|real|likely|clear|good|bad|bit|lot|few|word|new|person|because|is|has|was|item|belongs|category)\b', '', resp)
        ab_matches = re.findall(r'\b([ab])\b', filtered)
        if ab_matches:
            is_correct = ab_matches[-1] == ans
        else:
            is_correct = False

    elif type == "authority_bias_detection":
        # Milgram (1963): evaluate evidence vs source authority
        filtered = re.sub(r'\ba\s+(?:more|very|real|likely|clear|good|bad|bit|lot|few|word|new|person|because|is|has|was|item|belongs|category)\b', '', resp)
        ab_matches = re.findall(r'\b([ab])\b', filtered)
        if ab_matches:
            is_correct = ab_matches[-1] == ans
        else:
            is_correct = False

    elif type == "moral_responsibility_attribution":
        # Cushman (2008): intentional vs accidental harm
        filtered = re.sub(r'\ba\s+(?:more|very|real|likely|clear|good|bad|bit|lot|few|word|new|person|because|is|has|was|item|belongs|category)\b', '', resp)
        ab_matches = re.findall(r'\b([ab])\b', filtered)
        if ab_matches:
            is_correct = ab_matches[-1] == ans
        else:
            is_correct = False

    elif type == "social_norm_enforcement":
        # Fehr & Fischbacher (2004): predict third-party punishment of norm violations
        yn_matches = re.findall(r'\b(yes|no)\b', resp)
        if yn_matches:
            is_correct = yn_matches[-1] == ans
        else:
            is_correct = False

    elif type == "trust_calibration":
        # Berg et al. (1995): calibrate trust based on observed behavior
        yn_matches = re.findall(r'\b(yes|no)\b', resp)
        if yn_matches:
            is_correct = yn_matches[-1] == ans
        else:
            is_correct = False

    elif type == "empathic_accuracy":
        # Ickes (1993): infer emotional state from situational cues
        yn_matches = re.findall(r'\b(yes|no)\b', resp)
        if yn_matches:
            is_correct = yn_matches[-1] == ans
        else:
            is_correct = False

    elif type == "social_hierarchy_inference":
        # Sapolsky (2004): infer dominance from behavioral cues
        filtered = re.sub(r'\ba\s+(?:more|very|real|likely|clear|good|bad|bit|lot|few|word|new|person|because|is|has|was|item|belongs|category)\b', '', resp)
        ab_matches = re.findall(r'\b([ab])\b', filtered)
        if ab_matches:
