    elif type == "reciprocity_tracking":
        # Trivers (1971): track reciprocal exchange balance
        yn_matches = re.findall(r'\b(yes|no)\b', resp)
        ab_filtered = re.sub(r'\ba\s+(?:more|very|real|likely|clear|good|bad|bit|lot|few|word|new|person|because|is|has|was|item|belongs|category)\b', '', resp)
        ab_matches = re.findall(r'\b([ab])\b', ab_filtered)
        if ans in ('a', 'b') and ab_matches:
            is_correct = ab_matches[-1] == ans
        elif yn_matches:
            expected_yn = "yes" if ans == "a" else "no"
            is_correct = yn_matches[-1] == expected_yn
        else:
            is_correct = False

    elif type == "joint_attention":
        # Tomasello (1995): shared attentional focus
        yn_matches = re.findall(r'\b(yes|no)\b', resp)
        ab_filtered = re.sub(r'\ba\s+(?:more|very|real|likely|clear|good|bad|bit|lot|few|word|new|person|because|is|has|was|item|belongs|category)\b', '', resp)
        ab_matches = re.findall(r'\b([ab])\b', ab_filtered)
        if ans in ('a', 'b') and ab_matches:
            is_correct = ab_matches[-1] == ans
        elif yn_matches:
            expected_yn = "yes" if ans == "a" else "no"
            is_correct = yn_matches[-1] == expected_yn
        else:
