        ab_filtered = re.sub(r'\ba\s+(?:more|very|real|likely|clear|good|bad|bit|lot|few|word|new|person|because|is|has|was|item|belongs|category)\b', '', resp)
        ab_matches = re.findall(r'\b([ab])\b', ab_filtered)
        if ab_matches:
            is_correct = ab_matches[-1] == ans
        else:
            is_correct = False

    elif type == "sorrowful_amusement_detection":
        ab_filtered = re.sub(r'\ba\s+(?:more|very|real|likely|clear|good|bad|bit|lot|few|word|new|person|because|is|has|was|item|belongs|category)\b', '', resp)
        ab_matches = re.findall(r'\b([ab])\b', ab_filtered)
        if ab_matches:
            is_correct = ab_matches[-1] == ans
        else:
            is_correct = False

    else:
        is_correct = ans in resp

    kbench.assertions.assert_true(is_correct,
        expectation=f"Expected '{answer}', got '{response.strip()[:200]}'. "
                    f"Type: {type}, ToM: {tom_order}")
    return is_correct
